cat << 'EOF' > /tmp/test_stackalloc_nint.cs
using System;

Span<nint> span = stackalloc nint[4];
span[0] = 42;
span[1] = nint.MaxValue;
span[2] = nint.MinValue;
span[3] = (nint)123456789;

Console.WriteLine($"Length: {span.Length}");
Console.WriteLine($"sizeof(nint): {sizeof(nint)}");
for (int i = 0; i < span.Length; i++)
    Console.WriteLine($"  span[{i}] = {span[i]}");

Console.WriteLine("Success: stackalloc Span<nint> works!");
EOF
